using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// ── Notes store ──────────────────────────────────────────────────────────
var notes = new List<NoteEntry>();

// ── Tools ────────────────────────────────────────────────────────────────

[Description("Searches the web for the given query and returns a summary of the top results.")]
static async Task<string> SearchWeb(
    [Description("The search query to look up")] string query,
    CancellationToken cancellationToken)
{
    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd(
        "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

    var encoded = WebUtility.UrlEncode(query);
    var url = $"https://lite.duckduckgo.com/lite/?q={encoded}";

    var html = await http.GetStringAsync(url, cancellationToken);

    // Extract text snippets from the DuckDuckGo Lite results page
    var stripped = Regex.Replace(html, "<[^>]+>", " ");
    stripped = Regex.Replace(stripped, @"\s+", " ").Trim();

    const int maxLen = 3000;
    if (stripped.Length > maxLen)
        stripped = stripped[..maxLen] + "…";

    return string.IsNullOrWhiteSpace(stripped)
        ? "No results found."
        : stripped;
}

[Description("Saves a research note with a title and content for later reference.")]
string AddNote(
    [Description("Short title for the note")] string title,
    [Description("The note content")] string content)
{
    notes.Add(new NoteEntry(title, content));
    return $"Note saved: \"{title}\" ({notes.Count} total notes).";
}

[Description("Retrieves all saved research notes.")]
string GetNotes()
{
    if (notes.Count == 0)
        return "No notes saved yet.";

    var sb = new StringBuilder();
    for (var i = 0; i < notes.Count; i++)
    {
        sb.AppendLine($"--- Note {i + 1}: {notes[i].Title} ---");
        sb.AppendLine(notes[i].Content);
        sb.AppendLine();
    }

    return sb.ToString();
}

// ── Build AI tools from the local functions ──────────────────────────────
var tools = new AIFunction[]
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(AddNote),
    AIFunctionFactory.Create(GetNotes),
};

// ── Build chat‑client pipeline ───────────────────────────────────────────
IChatClient chatClient = new ChatClientBuilder(
        new OpenAI.OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
    .UseFunctionInvocation(o => o.MaximumIterationsPerRequest = 10)
    .Build();

// ── Create the agent ─────────────────────────────────────────────────────
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. When given a topic you must:
        1. Search the web multiple times to gather diverse information about the topic.
        2. Save key findings as notes using the add_note tool (use clear, concise titles).
        3. After you have gathered enough information (at least 3 searches and 3 notes),
           retrieve your notes and produce a well-structured summary.

        Always cite the information source when saving notes. Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "Researches a topic by searching the web and summarizing findings",
    tools: tools);

// ── Prompt the user ──────────────────────────────────────────────────────
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 60));
Console.WriteLine();

// ── Run the agent (streaming) ────────────────────────────────────────────
await foreach (var update in agent.RunStreamingAsync(
    [new ChatMessage(ChatRole.User, $"Research this topic and provide a comprehensive summary: {topic}")],
    new AgentSession()))
{
    Console.Write(update.Text);
}

Console.WriteLine();
Console.WriteLine();
Console.WriteLine(new string('─', 60));
Console.WriteLine($"Research complete. {notes.Count} note(s) were taken.");

// ── Types ────────────────────────────────────────────────────────────────
internal sealed record NoteEntry(string Title, string Content);

